# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

from ariadne import QueryType, ObjectType, make_executable_schema, load_schema_from_path
from ariadne.asgi import GraphQL

# Define schema using SDL
type_defs = """
    type User {
        username: String!
        bio: String
        email: String @private
        phone: String @private
        address: String @private
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        user(username: String!): User
        posts: [Post!]!
    }
"""

# Define types and resolvers
query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")

users_db = [
    {"username": "john_doe", "bio": "Software Developer", "email": "john@example.com", "phone": "123-456-7890", "address": "123 Main St"},
    {"username": "jane_smith", "bio": "Data Scientist", "email": "jane@example.com", "phone": "098-765-4321", "address": "456 Elm St"}
]

posts_db = [
    {"id": "1", "title": "GraphQL Basics", "content": "Introduction to GraphQL", "author": "john_doe"},
    {"id": "2", "title": "Advanced Python", "content": "Python Tips and Tricks", "author": "jane_smith"}
]

@query.field("user")
def resolve_user(_, info, username):
    return next((user for user in users_db if user["username"] == username), None)

@query.field("posts")
def resolve_posts(_, info):
    return posts_db

@post_type.field("author")
def resolve_author(post, _):
    return next((user for user in users_db if user["username"] == post["author"]), None)

schema = make_executable_schema(type_defs, [query, user_type, post_type])

# Middleware to set current_user
async def auth_middleware(request, call_next):
    request.state.current_user = {"username": "john_doe"}  # Example user
    response = await call_next(request)
    return response

app = GraphQL(schema, middleware=[auth_middleware])